package quota

import (
	"context"
	"testing"
	"time"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/policy/api"
)

// mockResource implements resource.Resource[*cilium_v2.CiliumNetworkPolicy]
type mockResource struct {
	eventsChan chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *mockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.eventsChan
}

func (m *mockResource) Store(context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, nil
}

func (m *mockResource) Observe(ctx context.Context, next func(resource.Event[*cilium_v2.CiliumNetworkPolicy])) error {
	return nil
}

func newMockResource() *mockResource {
	return &mockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()
	maxPerNamespace := 5

	controller := NewPolicyQuotaController(log, mockRes, maxPerNamespace)

	t.Run("quota not exceeded", func(t *testing.T) {
		err := controller.CheckQuota("default")
		assert.NoError(t, err, "should not exceed quota when no policies exist")
	})

	t.Run("quota exceeded", func(t *testing.T) {
		// Simulate 5 policies in the namespace
		controller.mu.Lock()
		controller.policyCount["test"] = 5
		controller.mu.Unlock()

		err := controller.CheckQuota("test")
		assert.Error(t, err, "should exceed quota when count equals max")
		assert.Contains(t, err.Error(), "policy quota exceeded")
	})

	t.Run("quota exactly at limit", func(t *testing.T) {
		controller.mu.Lock()
		controller.policyCount["limited"] = 5
		controller.mu.Unlock()

		err := controller.CheckQuota("limited")
		assert.Error(t, err, "should fail when at exact limit")
	})
}

func TestPolicyQuotaController_GetPolicyCount(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 10)

	t.Run("empty namespace", func(t *testing.T) {
		count := controller.GetPolicyCount("nonexistent")
		assert.Equal(t, 0, count, "should return 0 for nonexistent namespace")
	})

	t.Run("populated namespace", func(t *testing.T) {
		controller.mu.Lock()
		controller.policyCount["default"] = 3
		controller.mu.Unlock()

		count := controller.GetPolicyCount("default")
		assert.Equal(t, 3, count, "should return correct count")
	})
}

func TestPolicyQuotaController_GetNamespacePolicyCounts(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 10)

	t.Run("empty counts", func(t *testing.T) {
		counts := controller.GetNamespacePolicyCounts()
		assert.Empty(t, counts, "should return empty map initially")
	})

	t.Run("multiple namespaces", func(t *testing.T) {
		controller.mu.Lock()
		controller.policyCount["default"] = 2
		controller.policyCount["kube-system"] = 1
		controller.policyCount["test"] = 5
		controller.mu.Unlock()

		counts := controller.GetNamespacePolicyCounts()
		assert.Equal(t, 3, len(counts), "should return all namespaces")
		assert.Equal(t, 2, counts["default"])
		assert.Equal(t, 1, counts["kube-system"])
		assert.Equal(t, 5, counts["test"])
	})

	t.Run("copy isolation", func(t *testing.T) {
		controller.mu.Lock()
		controller.policyCount["default"] = 1
		controller.mu.Unlock()

		counts1 := controller.GetNamespacePolicyCounts()
		counts1["default"] = 999

		counts2 := controller.GetNamespacePolicyCounts()
		assert.Equal(t, 1, counts2["default"], "modifications to returned map should not affect controller")
	})
}

func TestPolicyQuotaController_onPolicyUpsert(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 10)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	t.Run("increment count", func(t *testing.T) {
		controller.onPolicyUpsert(policy)
		assert.Equal(t, 1, controller.GetPolicyCount("default"))

		controller.onPolicyUpsert(policy)
		assert.Equal(t, 2, controller.GetPolicyCount("default"))
	})

	t.Run("multiple namespaces", func(t *testing.T) {
		controller := NewPolicyQuotaController(log, mockRes, 10)

		policy1 := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "policy1",
				Namespace: "ns1",
			},
		}

		policy2 := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "policy2",
				Namespace: "ns2",
			},
		}

		controller.onPolicyUpsert(policy1)
		controller.onPolicyUpsert(policy2)
		controller.onPolicyUpsert(policy1)

		assert.Equal(t, 2, controller.GetPolicyCount("ns1"))
		assert.Equal(t, 1, controller.GetPolicyCount("ns2"))
	})
}

func TestPolicyQuotaController_onPolicyDelete(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 10)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	t.Run("decrement count", func(t *testing.T) {
		controller.onPolicyUpsert(policy)
		controller.onPolicyUpsert(policy)
		assert.Equal(t, 2, controller.GetPolicyCount("default"))

		controller.onPolicyDelete(policy)
		assert.Equal(t, 1, controller.GetPolicyCount("default"))

		controller.onPolicyDelete(policy)
		assert.Equal(t, 0, controller.GetPolicyCount("default"))
	})

	t.Run("delete nonexistent", func(t *testing.T) {
		controller := NewPolicyQuotaController(log, mockRes, 10)
		controller.onPolicyDelete(policy)
		assert.Equal(t, 0, controller.GetPolicyCount("default"))
	})

	t.Run("cleanup empty namespace", func(t *testing.T) {
		controller := NewPolicyQuotaController(log, mockRes, 10)
		controller.onPolicyUpsert(policy)
		controller.onPolicyDelete(policy)

		counts := controller.GetNamespacePolicyCounts()
		assert.Empty(t, counts, "empty namespaces should be removed from map")
	})
}

func TestPolicyQuotaController_Run(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 5)

	t.Run("context cancellation", func(t *testing.T) {
		ctx, cancel := context.WithCancel(context.Background())

		go func() {
			time.Sleep(100 * time.Millisecond)
			cancel()
		}()

		err := controller.Run(ctx)
		require.Error(t, err, "should return error on context cancellation")
		assert.Equal(t, context.Canceled, err)
	})

	t.Run("process upsert event", func(t *testing.T) {
		ctx, cancel := context.WithCancel(context.Background())
		defer cancel()

		mockRes := newMockResource()
		controller := NewPolicyQuotaController(log, mockRes, 5)

		policy := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-policy",
				Namespace: "default",
			},
		}

		// Send event in goroutine
		go func() {
			mockEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
				Kind:   resource.Upsert,
				Object: policy,
				Key:    resource.Key{Name: "test-policy", Namespace: "default"},
			}
			mockEvent.done = make(chan error, 1)
			mockRes.eventsChan <- mockEvent
		}()

		// Run controller in goroutine
		done := make(chan error, 1)
		go func() {
			time.Sleep(200 * time.Millisecond)
			cancel()
			done <- controller.Run(ctx)
		}()

		// Wait for run to complete
		<-done

		// Check that policy count was updated
		assert.Equal(t, 1, controller.GetPolicyCount("default"))
	})

	t.Run("process delete event", func(t *testing.T) {
		ctx, cancel := context.WithCancel(context.Background())
		defer cancel()

		mockRes := newMockResource()
		controller := NewPolicyQuotaController(log, mockRes, 5)

		policy := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-policy",
				Namespace: "default",
			},
		}

		// Set initial count
		controller.onPolicyUpsert(policy)
		assert.Equal(t, 1, controller.GetPolicyCount("default"))

		// Send delete event in goroutine
		go func() {
			mockEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
				Kind:   resource.Delete,
				Object: policy,
				Key:    resource.Key{Name: "test-policy", Namespace: "default"},
			}
			mockEvent.done = make(chan error, 1)
			mockRes.eventsChan <- mockEvent
		}()

		// Run controller in goroutine
		done := make(chan error, 1)
		go func() {
			time.Sleep(200 * time.Millisecond)
			cancel()
			done <- controller.Run(ctx)
		}()

		// Wait for run to complete
		<-done

		// Check that policy count was decremented
		assert.Equal(t, 0, controller.GetPolicyCount("default"))
	})
}

func TestPolicyQuotaController_ThreadSafety(t *testing.T) {
	log := logrus.NewEntry(logrus.New())
	mockRes := newMockResource()

	controller := NewPolicyQuotaController(log, mockRes, 100)

	// Create policies
	policies := make([]*cilium_v2.CiliumNetworkPolicy, 0, 50)
	for i := 0; i < 50; i++ {
		policies = append(policies, &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "policy-" + string(rune(i)),
				Namespace: "default",
			},
		})
	}

	// Concurrent upserts
	done := make(chan struct{})
	for _, policy := range policies {
		go func(p *cilium_v2.CiliumNetworkPolicy) {
			controller.onPolicyUpsert(p)
			done <- struct{}{}
		}(policy)
	}

	for range policies {
		<-done
	}

	// Concurrent deletes
	for _, policy := range policies {
		go func(p *cilium_v2.CiliumNetworkPolicy) {
			controller.onPolicyDelete(p)
			done <- struct{}{}
		}(policy)
	}

	for range policies {
		<-done
	}

	assert.Equal(t, 0, controller.GetPolicyCount("default"))
}

