	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyQuotaController enforces per-namespace limits on CiliumNetworkPolicy resources
type PolicyQuotaController struct {
	log logrus.FieldLogger

	// CNP resource watcher
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]

	// maxPerNamespace defines the maximum number of CiliumNetworkPolicy resources per namespace
	maxPerNamespace int

	// mu protects the policyCount map
	mu sync.RWMutex

	// policyCount tracks the number of policies per namespace
	policyCount map[string]int
}

// NewPolicyQuotaController creates a new PolicyQuotaController
func NewPolicyQuotaController(
	log logrus.FieldLogger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log.WithField(logfields.LogSubsys, "policy-quota"),
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		policyCount:           make(map[string]int),
	}
}

// Run starts the PolicyQuotaController
func (pqc *PolicyQuotaController) Run(ctx context.Context) error {
	pqc.log.Info("Starting PolicyQuotaController")

	events := pqc.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			pqc.log.Info("PolicyQuotaController stopped")
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				pqc.log.Info("PolicyQuotaController event channel closed")
				return nil
			}

			var err error
			switch event.Kind {
			case resource.Upsert:
				err = pqc.onPolicyUpsert(event.Object)
			case resource.Delete:
				err = pqc.onPolicyDelete(event.Object)
			case resource.Sync:
				pqc.log.Debug("PolicyQuotaController synced with API server")
			}

			event.Done(err)
		}
	}
}

// onPolicyUpsert handles policy creation or update
func (pqc *PolicyQuotaController) onPolicyUpsert(policy *cilium_v2.CiliumNetworkPolicy) error {
	namespace := policy.GetNamespace()

	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	pqc.policyCount[namespace]++

	pqc.log.WithFields(logrus.Fields{
		logfields.K8sNamespace: namespace,
		"policy_count":         pqc.policyCount[namespace],
		"max_per_namespace":    pqc.maxPerNamespace,
	}).Debug("Policy upserted")

	return nil
}

// onPolicyDelete handles policy deletion
func (pqc *PolicyQuotaController) onPolicyDelete(policy *cilium_v2.CiliumNetworkPolicy) error {
	namespace := policy.GetNamespace()

	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	if count, exists := pqc.policyCount[namespace]; exists && count > 0 {
		pqc.policyCount[namespace]--
		if pqc.policyCount[namespace] == 0 {
			delete(pqc.policyCount, namespace)
		}
	}

	pqc.log.WithFields(logrus.Fields{
		logfields.K8sNamespace: namespace,
		"policy_count":         pqc.policyCount[namespace],
	}).Debug("Policy deleted")

	return nil
}

// CheckQuota checks if adding a new policy to the given namespace would exceed the quota
// Returns an error if the quota would be exceeded
func (pqc *PolicyQuotaController) CheckQuota(namespace string) error {
	pqc.mu.RLock()
	defer pqc.mu.RUnlock()

	currentCount := pqc.policyCount[namespace]

	if currentCount >= pqc.maxPerNamespace {
		err := fmt.Errorf(
			"policy quota exceeded in namespace %q: current=%d, max=%d",
			namespace,
			currentCount,
			pqc.maxPerNamespace,
		)
		pqc.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: namespace,
			"current_count":        currentCount,
			"max_per_namespace":    pqc.maxPerNamespace,
		}).Warn("Policy quota exceeded")
		return err
	}

	return nil
}

// GetPolicyCount returns the current number of policies in a namespace
func (pqc *PolicyQuotaController) GetPolicyCount(namespace string) int {
	pqc.mu.RLock()
	defer pqc.mu.RUnlock()
	return pqc.policyCount[namespace]
}

// GetNamespacePolicyCounts returns a copy of the policy count map
func (pqc *PolicyQuotaController) GetNamespacePolicyCounts() map[string]int {
	pqc.mu.RLock()
	defer pqc.mu.RUnlock()

	result := make(map[string]int, len(pqc.policyCount))
	for ns, count := range pqc.policyCount {
		result[ns] = count
	}
	return result
}
